/**
 * NEON STRIKE - Space Shooter
 * A polished 2D arcade shooter using HTML5 Canvas.
 */

// --- Types & Interfaces ---

interface Point {
    x: number;
    y: number;
}

// --- Utilities ---

const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;

// --- Entity Classes ---

class Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    radius: number;
    color: string;
    life: number;
    opacity: number;

    constructor(x: number, y: number, color: string) {
        this.x = x;
        this.y = y;
        this.vx = randomRange(-3, 3);
        this.vy = randomRange(-3, 3);
        this.radius = randomRange(1, 3);
        this.color = color;
        this.life = 1.0;
        this.opacity = 1.0;
    }

    update() {
        this.x += this.vx;
        this.y += this.vy;
        this.life -= 0.02;
        this.opacity = Math.max(0, this.life);
    }

    draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.globalAlpha = this.opacity;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.fill();
        ctx.restore();
    }
}

class Bullet {
    x: number;
    y: number;
    width: number = 4;
    height: number = 15;
    speed: number = 8;
    color: string = '#00f2ff';

    constructor(x: number, y: number) {
        this.x = x - this.width / 2;
        this.y = y;
    }

    update() {
        this.y -= this.speed;
    }

    draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.shadowBlur = 10;
        ctx.shadowColor = this.color;
        ctx.fillStyle = this.color;
        ctx.fillRect(this.x, this.y, this.width, this.height);
        ctx.restore();
    }
}

class Enemy {
    x: number;
    y: number;
    width: number;
    height: number;
    speed: number;
    hue: number;

    constructor(canvasWidth: number, speedMultiplier: number) {
        this.width = randomRange(30, 50);
        this.height = this.width * 0.8;
        this.x = randomRange(0, canvasWidth - this.width);
        this.y = -this.height;
        this.speed = randomRange(2, 4) * speedMultiplier;
        this.hue = randomRange(300, 340); // Pink/Magenta range
    }

    update() {
        this.y += this.speed;
    }

    draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.shadowBlur = 15;
        ctx.shadowColor = `hsl(${this.hue}, 100%, 50%)`;
        ctx.strokeStyle = `hsl(${this.hue}, 100%, 70%)`;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y + this.height);
        ctx.lineTo(this.x, this.y);
        ctx.lineTo(this.x + this.width, this.y);
        ctx.closePath();
        ctx.stroke();

        // Inner core
        ctx.fillStyle = `hsla(${this.hue}, 100%, 50%, 0.3)`;
        ctx.fill();
        ctx.restore();
    }
}

class Player {
    x: number;
    y: number;
    width: number = 40;
    height: number = 40;
    vx: number = 0;
    friction: number = 0.9;
    acceleration: number = 1.2;
    maxSpeed: number = 8;
    color: string = '#00f2ff';

    constructor(canvasWidth: number, canvasHeight: number) {
        this.x = canvasWidth / 2 - this.width / 2;
        this.y = canvasHeight - 80;
    }

    move(dir: number) {
        this.vx += dir * this.acceleration;
    }

    update(canvasWidth: number) {
        this.vx *= this.friction;
        this.x += this.vx;

        // Keep in bounds
        if (this.x < 0) {
            this.x = 0;
            this.vx = 0;
        }
        if (this.x > canvasWidth - this.width) {
            this.x = canvasWidth - this.width;
            this.vx = 0;
        }
    }

    draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.shadowBlur = 20;
        ctx.shadowColor = this.color;
        ctx.strokeStyle = this.color;
        ctx.lineWidth = 3;

        // Ship shape
        ctx.beginPath();
        ctx.moveTo(this.x + this.width / 2, this.y); // Top
        ctx.lineTo(this.x, this.y + this.height); // Bottom left
        ctx.lineTo(this.x + this.width / 2, this.y + this.height * 0.7); // Middle indent
        ctx.lineTo(this.x + this.width, this.y + this.height); // Bottom right
        ctx.closePath();
        ctx.stroke();

        // Engine glow
        const engineGlow = ctx.createRadialGradient(
            this.x + this.width / 2, this.y + this.height, 0,
            this.x + this.width / 2, this.y + this.height, 15
        );
        engineGlow.addColorStop(0, this.color);
        engineGlow.addColorStop(1, 'transparent');
        ctx.fillStyle = engineGlow;
        ctx.fillRect(this.x + this.width / 4, this.y + this.height * 0.7, this.width / 2, 20);

        ctx.restore();
    }
}

// --- Game Engine ---

class Game {
    canvas: HTMLCanvasElement;
    ctx: CanvasRenderingContext2D;
    player: Player;
    bullets: Bullet[] = [];
    enemies: Enemy[] = [];
    particles: Particle[] = [];
    stars: {x: number, y: number, size: number, speed: number}[] = [];

    score: number = 0;
    lives: number = 3;
    gameState: 'START' | 'PLAYING' | 'GAMEOVER' = 'START';

    keys: { [key: string]: boolean } = {};
    lastFireTime: number = 0;
    fireRate: number = 200; // ms
    enemySpawnTimer: number = 0;
    enemySpawnRate: number = 1500; // ms start
    startTime: number = 0;

    constructor() {
        this.canvas = document.getElementById('gameCanvas') as HTMLCanvasElement;
        this.ctx = this.canvas.getContext('2d')!;
        this.resize();
        window.addEventListener('resize', () => this.resize());

        this.player = new Player(this.canvas.width, this.canvas.height);
        this.initStars();

        // Event Listeners
        window.addEventListener('keydown', (e) => this.keys[e.code] = true);
        window.addEventListener('keyup', (e) => this.keys[e.code] = false);

        document.getElementById('start-btn')?.addEventListener('click', () => this.start());
        document.getElementById('restart-btn')?.addEventListener('click', () => this.start());

        this.loop();
    }

    resize() {
        this.canvas.width = window.innerWidth;
        this.canvas.height = window.innerHeight;
    }

    initStars() {
        this.stars = [];
        for (let i = 0; i < 150; i++) {
            this.stars.push({
                x: Math.random() * this.canvas.width,
                y: Math.random() * this.canvas.height,
                size: Math.random() * 2,
                speed: Math.random() * 0.5 + 0.2
            });
        }
    }

    start() {
        this.gameState = 'PLAYING';
        this.score = 0;
        this.lives = 3;
        this.bullets = [];
        this.enemies = [];
        this.particles = [];
        this.enemySpawnRate = 1500;
        this.startTime = Date.now();
        this.player = new Player(this.canvas.width, this.canvas.height);

        document.getElementById('start-screen')?.classList.add('hidden');
        document.getElementById('game-over-screen')?.classList.add('hidden');
        document.getElementById('hud')?.classList.remove('hidden');
        this.updateHUD();
    }

    gameOver() {
        this.gameState = 'GAMEOVER';
        document.getElementById('game-over-screen')?.classList.remove('hidden');
        document.getElementById('hud')?.classList.add('hidden');
        document.getElementById('final-score')!.innerText = this.score.toString();
    }

    updateHUD() {
        document.getElementById('score-val')!.innerText = this.score.toString();
        document.getElementById('lives-val')!.innerText = this.lives.toString();
    }

    createExplosion(x: number, y: number, color: string) {
        for (let i = 0; i < 15; i++) {
            this.particles.push(new Particle(x, y, color));
        }
    }

    handleInput() {
        if (this.keys['ArrowLeft'] || this.keys['KeyA']) this.player.move(-1);
        if (this.keys['ArrowRight'] || this.keys['KeyD']) this.player.move(1);
        if (this.keys['Space']) {
            const now = Date.now();
            if (now - this.lastFireTime > this.fireRate) {
                this.bullets.push(new Bullet(this.player.x + this.player.width / 2, this.player.y));
                this.lastFireTime = now;
            }
        }
    }

    update(deltaTime: number) {
        if (this.gameState !== 'PLAYING') return;

        this.handleInput();
        this.player.update(this.canvas.width);

        // Update Bullets
        this.bullets.forEach((b, i) => {
            b.update();
            if (b.y < -20) this.bullets.splice(i, 1);
        });

        // Spawn Enemies
        this.enemySpawnTimer += deltaTime;
        if (this.enemySpawnTimer > this.enemySpawnRate) {
            const difficultyMultiplier = 1 + (Date.now() - this.startTime) / 60000;
            this.enemies.push(new Enemy(this.canvas.width, difficultyMultiplier));
            this.enemySpawnTimer = 0;
            // Gradually decrease spawn interval
            this.enemySpawnRate = Math.max(400, 1500 - (this.score / 100) * 50);
        }

        // Update Enemies
        this.enemies.forEach((e, i) => {
            e.update();

            // Off screen
            if (e.y > this.canvas.height) {
                this.enemies.splice(i, 1);
            }

            // Player collision
            if (
                e.x < this.player.x + this.player.width &&
                e.x + e.width > this.player.x &&
                e.y < this.player.y + this.player.height &&
                e.y + e.height > this.player.y
            ) {
                this.enemies.splice(i, 1);
                this.lives--;
                this.createExplosion(this.player.x + this.player.width / 2, this.player.y + this.player.height / 2, '#ff00ea');
                this.updateHUD();
                if (this.lives <= 0) this.gameOver();
            }

            // Bullet collision
            this.bullets.forEach((b, bi) => {
                if (
                    b.x < e.x + e.width &&
                    b.x + b.width > e.x &&
                    b.y < e.y + e.height &&
                    b.y + b.height > e.y
                ) {
                    this.createExplosion(e.x + e.width / 2, e.y + e.height / 2, `hsl(${e.hue}, 100%, 50%)`);
                    this.enemies.splice(i, 1);
                    this.bullets.splice(bi, 1);
                    this.score += 10;
                    this.updateHUD();
                }
            });
        });

        // Particles
        this.particles.forEach((p, i) => {
            p.update();
            if (p.life <= 0) this.particles.splice(i, 1);
        });
    }

    draw() {
        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

        // Draw Stars
        this.ctx.fillStyle = 'white';
        this.stars.forEach(s => {
            this.ctx.globalAlpha = s.speed;
            this.ctx.beginPath();
            this.ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
            this.ctx.fill();
            s.y += s.speed;
            if (s.y > this.canvas.height) s.y = -10;
        });
        this.ctx.globalAlpha = 1;

        if (this.gameState === 'PLAYING') {
            this.player.draw(this.ctx);
            this.bullets.forEach(b => b.draw(this.ctx));
            this.enemies.forEach(e => e.draw(this.ctx));
            this.particles.forEach(p => p.draw(this.ctx));
        }
    }

    lastTime: number = 0;
    loop(timestamp: number = 0) {
        const deltaTime = timestamp - this.lastTime;
        this.lastTime = timestamp;

        this.update(deltaTime);
        this.draw();

        requestAnimationFrame((t) => this.loop(t));
    }
}

// Start Game Engine
new Game();

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { createRoot } from 'react-dom/client';

// --- Types & Interfaces ---

type GameState = 'START' | 'PLAYING' | 'BOSS_WARNING' | 'GAMEOVER';

interface Point { x: number; y: number; }

// --- Sound Engine (Synthesized) ---

class SoundEngine {
    ctx: AudioContext | null = null;

    init() {
        if (!this.ctx) this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    private playTone(freq: number, type: OscillatorType, duration: number, volume: number) {
        if (!this.ctx) return;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
        gain.gain.setValueAtTime(volume, this.ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(this.ctx.destination);
        osc.start();
        osc.stop(this.ctx.currentTime + duration);
    }

    shoot() { this.playTone(440, 'square', 0.1, 0.05); }
    explosion() { this.playTone(100, 'sawtooth', 0.3, 0.1); }
    hit() { this.playTone(150, 'sine', 0.2, 0.1); }
    bossSpawn() { this.playTone(80, 'sawtooth', 1.0, 0.1); }
}

const sounds = new SoundEngine();

// --- Game Entities ---

class Particle {
    x: number; y: number; vx: number; vy: number;
    life: number = 1.0;
    color: string;
    constructor(x: number, y: number, color: string) {
        this.x = x; this.y = y;
        this.vx = (Math.random() - 0.5) * 6;
        this.vy = (Math.random() - 0.5) * 6;
        this.color = color;
    }
    update() { this.x += this.vx; this.y += this.vy; this.life -= 0.02; }
}

class Boss {
    x: number; y: number; width: number = 120; height: number = 80;
    hp: number = 50; maxHp: number = 50;
    direction: number = 1;
    angle: number = 0;
    constructor(canvasWidth: number) {
        this.x = canvasWidth / 2 - 60;
        this.y = -100;
    }
    update(canvasWidth: number) {
        if (this.y < 100) this.y += 2;
        this.angle += 0.02;
        this.x += Math.sin(this.angle) * 3;
    }
}

// --- Main App Component ---

const App: React.FC = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [gameState, setGameState] = useState<GameState>('START');
    const [score, setScore] = useState(0);
    const [highScore, setHighScore] = useState(Number(localStorage.getItem('neonHigh') || 0));
    const [lives, setLives] = useState(3);
    const [bossHp, setBossHp] = useState<number | null>(null);
    const [isMobile, setIsMobile] = useState('ontouchstart' in window);

    // Engine Refs
    const gameData = useRef({
        player: { x: 0, y: 0, w: 40, h: 40, vx: 0, invul: 0 },
        bullets: [] as {x: number, y: number}[],
        bossBullets: [] as {x: number, y: number}[],
        enemies: [] as {x: number, y: number, w: number, h: number, s: number, hue: number}[],
        particles: [] as Particle[],
        stars: [] as {x: number, y: number, s: number, sp: number}[],
        boss: null as Boss | null,
        shake: 0,
        keys: {} as Record<string, boolean>,
        lastFire: 0,
        lastEnemySpawn: 0
    });

    const initStars = (w: number, h: number) => {
        gameData.current.stars = Array.from({ length: 100 }, () => ({
            x: Math.random() * w, y: Math.random() * h, s: Math.random() * 2, sp: Math.random() * 0.5 + 0.1
        }));
    };

    const startGame = () => {
        sounds.init();
        setGameState('PLAYING');
        setScore(0);
        setLives(3);
        setBossHp(null);
        gameData.current.boss = null;
        gameData.current.enemies = [];
        gameData.current.bullets = [];
        gameData.current.bossBullets = [];
        gameData.current.player.invul = 0;
        gameData.current.lastEnemySpawn = performance.now();
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d')!;
        let animationFrameId: number;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            gameData.current.player.x = canvas.width / 2;
            gameData.current.player.y = canvas.height - 80;
            initStars(canvas.width, canvas.height);
        };
        resize();
        window.addEventListener('resize', resize);

        const handleInput = () => {
            const { keys, player } = gameData.current;
            if (keys['ArrowLeft'] || keys['KeyA']) player.vx -= 1.5;
            if (keys['ArrowRight'] || keys['KeyD']) player.vx += 1.5;
            if (keys['Space']) fire();
        };

        const fire = () => {
            const now = performance.now();
            if (now - gameData.current.lastFire > 200) {
                gameData.current.bullets.push({ 
                    x: gameData.current.player.x + 18, 
                    y: gameData.current.player.y 
                });
                gameData.current.lastFire = now;
                sounds.shoot();
            }
        };

        const update = (time: number) => {
            const { player, enemies, bullets, particles, boss, stars, bossBullets } = gameData.current;

            if (gameState === 'PLAYING') {
                handleInput();

                // Player physics
                player.vx *= 0.9;
                player.x += player.vx;
                player.x = Math.max(0, Math.min(canvas.width - player.w, player.x));
                if (player.invul > 0) player.invul--;

                // Stars
                stars.forEach(s => {
                    s.y += s.sp;
                    if (s.y > canvas.height) s.y = 0;
                });

                // Bullets
                bullets.forEach((b, i) => {
                    b.y -= 10;
                    if (b.y < -20) bullets.splice(i, 1);
                });

                // Boss Bullets
                bossBullets.forEach((b, i) => {
                    b.y += 5;
                    if (b.y > canvas.height) bossBullets.splice(i, 1);
                    // Collision with player
                    if (b.x > player.x && b.x < player.x + player.w && b.y > player.y && b.y < player.y + player.h && player.invul === 0) {
                        hitPlayer();
                        bossBullets.splice(i, 1);
                    }
                });

                // Enemy Spawn
                if (!boss && time - gameData.current.lastEnemySpawn > Math.max(400, 1500 - score / 2)) {
                    enemies.push({
                        x: Math.random() * (canvas.width - 40),
                        y: -50, w: 40, h: 40,
                        s: 2 + Math.random() * 3,
                        hue: Math.random() * 360
                    });
                    gameData.current.lastEnemySpawn = time;
                }

                // Boss Logic
                if (score > 0 && score % 500 === 0 && !boss) {
                    gameData.current.boss = new Boss(canvas.width);
                    sounds.bossSpawn();
                }

                if (boss) {
                    boss.update(canvas.width);
                    setBossHp(boss.hp);
                    if (Math.random() < 0.02) {
                        bossBullets.push({ x: boss.x + boss.width/2, y: boss.y + boss.height });
                    }
                    // Boss collision with bullets
                    bullets.forEach((b, bi) => {
                        if (b.x > boss.x && b.x < boss.x + boss.width && b.y > boss.y && b.y < boss.y + boss.height) {
                            boss.hp--;
                            bullets.splice(bi, 1);
                            if (boss.hp <= 0) {
                                sounds.explosion();
                                gameData.current.boss = null;
                                setScore(s => s + 200);
                                setBossHp(null);
                            }
                        }
                    });
                }

                // Enemies Update
                enemies.forEach((e, i) => {
                    e.y += e.s;
                    if (e.y > canvas.height) enemies.splice(i, 1);

                    // Bullet Collision
                    bullets.forEach((b, bi) => {
                        if (b.x > e.x && b.x < e.x + e.w && b.y > e.y && b.y < e.y + e.h) {
                            enemies.splice(i, 1);
                            bullets.splice(bi, 1);
                            setScore(s => s + 10);
                            for(let k=0; k<10; k++) particles.push(new Particle(e.x+e.w/2, e.y+e.h/2, `hsl(${e.hue}, 100%, 50%)`));
                            sounds.explosion();
                        }
                    });

                    // Player Collision
                    if (e.x < player.x + player.w && e.x + e.w > player.x && e.y < player.y + player.h && e.y + e.h > player.y && player.invul === 0) {
                        enemies.splice(i, 1);
                        hitPlayer();
                    }
                });

                // Particles
                particles.forEach((p, i) => {
                    p.update();
                    if (p.life <= 0) particles.splice(i, 1);
                });
            }

            if (gameData.current.shake > 0) gameData.current.shake *= 0.9;
        };

        const hitPlayer = () => {
            setLives(l => {
                const next = l - 1;
                if (next <= 0) setGameState('GAMEOVER');
                return next;
            });
            gameData.current.player.invul = 60;
            gameData.current.shake = 20;
            sounds.hit();
        };

        const draw = () => {
            ctx.fillStyle = '#050505';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            const { player, enemies, bullets, particles, boss, stars, shake, bossBullets } = gameData.current;

            ctx.save();
            if (shake > 0.1) ctx.translate((Math.random()-0.5)*shake, (Math.random()-0.5)*shake);

            // Stars
            ctx.fillStyle = '#fff';
            stars.forEach(s => {
                ctx.globalAlpha = s.sp;
                ctx.fillRect(s.x, s.y, s.s, s.s);
            });
            ctx.globalAlpha = 1;

            // Player
            if (player.invul % 10 < 5) {
                ctx.shadowBlur = 15;
                ctx.shadowColor = '#00f2ff';
                ctx.strokeStyle = '#00f2ff';
                ctx.lineWidth = 3;
                ctx.beginPath();
                ctx.moveTo(player.x + 20, player.y);
                ctx.lineTo(player.x, player.y + 40);
                ctx.lineTo(player.x + 40, player.y + 40);
                ctx.closePath();
                ctx.stroke();
            }

            // Bullets
            ctx.fillStyle = '#00f2ff';
            bullets.forEach(b => ctx.fillRect(b.x, b.y, 4, 15));

            // Boss Bullets
            ctx.fillStyle = '#ff0044';
            bossBullets.forEach(b => ctx.fillRect(b.x, b.y, 8, 8));

            // Enemies
            enemies.forEach(e => {
                ctx.strokeStyle = `hsl(${e.hue}, 100%, 50%)`;
                ctx.strokeRect(e.x, e.y, e.w, e.h);
            });

            // Boss
            if (boss) {
                ctx.strokeStyle = '#ff00ea';
                ctx.lineWidth = 5;
                ctx.strokeRect(boss.x, boss.y, boss.width, boss.height);
                ctx.fillStyle = 'rgba(255, 0, 234, 0.2)';
                ctx.fillRect(boss.x, boss.y, boss.width, boss.height);
            }

            // Particles
            particles.forEach(p => {
                ctx.globalAlpha = p.life;
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, 2, 0, Math.PI*2);
                ctx.fill();
            });
            ctx.globalAlpha = 1;

            ctx.restore();
            animationFrameId = requestAnimationFrame((t) => {
                update(t);
                draw();
            });
        };

        const onKeyDown = (e: KeyboardEvent) => gameData.current.keys[e.code] = true;
        const onKeyUp = (e: KeyboardEvent) => gameData.current.keys[e.code] = false;
        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        draw();
        return () => {
            cancelAnimationFrame(animationFrameId);
            window.removeEventListener('keydown', onKeyDown);
            window.removeEventListener('keyup', onKeyUp);
            window.removeEventListener('resize', resize);
        };
    }, [gameState, score]);

    useEffect(() => {
        if (score > highScore) {
            setHighScore(score);
            localStorage.setItem('neonHigh', score.toString());
        }
    }, [score]);

