import React, { useEffect, useRef, useState } from 'react';
import { createRoot } from 'react-dom/client';

// --- Types & Constants ---

type GameState = 'START' | 'PLAYING' | 'GAMEOVER';
type EnemyType = 'BASIC' | 'OSCILLATOR' | 'INTERCEPTOR' | 'STRAFER';
type PowerType = 'RAPID' | 'SHIELD';
type BossState = 'CRUISE' | 'BARRAGE' | 'CHARGE' | 'DYING';

const BOSS_BASE_HP = 50;
const POWERUP_CHANCE = 0.15;

// --- Sound Engine ---

class SoundEngine {
    ctx: AudioContext | null = null;
    noiseBuffer: AudioBuffer | null = null;

    init() {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
            this.noiseBuffer = this.createNoiseBuffer();
        }
    }

    private createNoiseBuffer() {
        if (!this.ctx) return null;
        const bufferSize = this.ctx.sampleRate * 2;
        const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
        const output = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) output[i] = Math.random() * 2 - 1;
        return buffer;
    }

    private playTone(freq: number, type: OscillatorType, duration: number, volume: number, ramp = true) {
        if (!this.ctx) return;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
        gain.gain.setValueAtTime(volume, this.ctx.currentTime);
        if (ramp) gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(this.ctx.destination);
        osc.start();
        osc.stop(this.ctx.currentTime + duration);
    }

    shoot() {
        if (!this.ctx || !this.noiseBuffer) return;
        const noiseSource = this.ctx.createBufferSource();
        noiseSource.buffer = this.noiseBuffer;
        const noiseGain = this.ctx.createGain();
        noiseGain.gain.setValueAtTime(0.02, this.ctx.currentTime);
        noiseGain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.1);
        noiseSource.connect(noiseGain);
        noiseGain.connect(this.ctx.destination);
        noiseSource.start();
        this.playTone(880, 'sine', 0.05, 0.01);
    }

    explosion() { this.playTone(60, 'sawtooth', 0.4, 0.08); }
    hit() { this.playTone(150, 'sine', 0.2, 0.05); }
    powerup() { this.playTone(600, 'sine', 0.3, 0.05); this.playTone(800, 'sine', 0.4, 0.03); }
    bossSpawn() { this.playTone(80, 'sawtooth', 1.5, 0.1); }
}

const sounds = new SoundEngine();

// --- Game Classes ---

class Particle {
    x: number; y: number; vx: number; vy: number;
    life: number = 1.0; color: string;
    constructor(x: number, y: number, color: string) {
        this.x = x; this.y = y;
        this.vx = (Math.random() - 0.5) * 8;
        this.vy = (Math.random() - 0.5) * 8;
        this.color = color;
    }
    update() { this.x += this.vx; this.y += this.vy; this.life -= 0.02; }
}

class PowerUp {
    x: number; y: number; type: PowerType; w = 20; h = 20;
    constructor(x: number, y: number, type: PowerType) {
        this.x = x; this.y = y; this.type = type;
    }
    update() { this.y += 2; }
}

class Enemy {
    x: number; y: number; w = 40; h = 40; s: number; hue: number;
    type: EnemyType; angle = 0; spawnX: number;
    constructor(canvasWidth: number, speedMult: number) {
        const types: EnemyType[] = ['BASIC', 'OSCILLATOR', 'INTERCEPTOR', 'STRAFER'];
        this.type = types[Math.floor(Math.random() * types.length)];
        this.spawnX = Math.random() * (canvasWidth - 40);
        this.x = this.spawnX;
        this.y = -50;
        this.hue = this.type === 'BASIC' ? 200 : this.type === 'OSCILLATOR' ? 300 : this.type === 'INTERCEPTOR' ? 120 : 40;
        this.s = (this.type === 'INTERCEPTOR' ? 6 : 2 + Math.random() * 2) * speedMult;
    }
    update() {
        this.y += this.s;
        if (this.type === 'OSCILLATOR') {
            this.angle += 0.05;
            this.x = this.spawnX + Math.sin(this.angle) * 100;
        } else if (this.type === 'STRAFER') {
            if (Math.random() < 0.02) this.angle = (Math.random() - 0.5) * 10;
            this.x += this.angle;
        }
    }
}

class Boss {
    x: number; y: number; w = 150; h = 100;
    hp: number; maxHp: number;
    state: BossState = 'CRUISE';
    timer = 0; angle = 0; targetY = 100;
    constructor(canvasWidth: number, hp: number) {
        this.x = canvasWidth / 2 - 75;
        this.y = -150;
        this.hp = hp;
        this.maxHp = hp;
    }
    update(canvasWidth: number, time: number) {
        if (this.state === 'DYING') return;

        this.timer++;
        if (this.y < this.targetY) this.y += 2;

        if (this.state === 'CRUISE') {
            this.angle += 0.02;
            this.x = (canvasWidth / 2 - 75) + Math.sin(this.angle) * 150;
            if (this.timer > 300) {
                this.state = Math.random() > 0.5 ? 'BARRAGE' : 'CHARGE';
                this.timer = 0;
            }
        } else if (this.state === 'BARRAGE') {
            // Stay still
            if (this.timer > 150) {
                this.state = 'CRUISE';
                this.timer = 0;
            }
        } else if (this.state === 'CHARGE') {
            if (this.timer < 50) {
                this.y -= 1; // Anticipation
            } else if (this.timer < 100) {
                this.y += 15; // Charge
            } else {
                this.y -= 2; // Return
                if (this.y <= this.targetY) {
                    this.state = 'CRUISE';
                    this.timer = 0;
                }
            }
        }
    }
}

// --- App ---

const App: React.FC = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [gameState, setGameState] = useState<GameState>('START');
    const [score, setScore] = useState(0);
    const [highScore, setHighScore] = useState(Number(localStorage.getItem('galaxyHigh') || 0));
    const [lives, setLives] = useState(3);
    const [bossHp, setBossHp] = useState<{current: number, max: number} | null>(null);
    const [powerUps, setPowerActive] = useState<{rapid: number, shield: number}>({ rapid: 0, shield: 0 });

    const gameData = useRef({
        player: { x: 0, y: 0, w: 40, h: 40, vx: 0, invul: 0, shield: false },
        bullets: [] as {x: number, y: number}[],
        bossBullets: [] as {x: number, y: number, vx: number, vy: number}[],
        enemies: [] as Enemy[],
        powerups: [] as PowerUp[],
        particles: [] as Particle[],
        stars: [] as {x: number, y: number, s: number, sp: number, l: number}[],
        boss: null as Boss | null,
        shake: 0,
        keys: {} as Record<string, boolean>,
        lastFire: 0,
        lastEnemySpawn: 0,
        startTime: 0,
        bossDefeatedCount: 0
    });

    const initStars = (w: number, h: number) => {
        gameData.current.stars = Array.from({ length: 150 }, () => ({
            x: Math.random() * w, 
            y: Math.random() * h, 
            s: Math.random() * 3, 
            sp: 0, // Assigned by layer
            l: Math.floor(Math.random() * 3) // 0: Far, 1: Mid, 2: Near
        })).map(s => ({
            ...s,
            sp: (s.l + 1) * 0.4,
            s: (s.l + 1) * 0.8
        }));
    };

    const startGame = () => {
        sounds.init();
        setGameState('PLAYING');
        setScore(0);
        setLives(3);
        setPowerActive({ rapid: 0, shield: 0 });
        gameData.current = {
            ...gameData.current,
            boss: null, enemies: [], bullets: [], bossBullets: [], powerups: [],
            startTime: performance.now(), bossDefeatedCount: 0, score: 0
        };
        gameData.current.player.shield = false;
        gameData.current.player.invul = 0;
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d')!;
        let animationFrameId: number;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            gameData.current.player.x = canvas.width / 2 - 20;
            gameData.current.player.y = canvas.height - 100;
            initStars(canvas.width, canvas.height);
        };
        resize();
        window.addEventListener('resize', resize);

        const update = (time: number) => {
            const { player, enemies, bullets, particles, boss, stars, bossBullets, powerups, keys } = gameData.current;
            if (gameState !== 'PLAYING') return;

            // Difficulty Scale
            const playTimeMinutes = (time - gameData.current.startTime) / 60000;
            const speedMult = 1 + playTimeMinutes * 0.5;
            const spawnRate = Math.max(250, 1500 - (score / 15));

            // Input
            if (keys['ArrowLeft'] || keys['KeyA']) player.vx -= 1.8;
            if (keys['ArrowRight'] || keys['KeyD']) player.vx += 1.8;
            player.vx *= 0.88;
            player.x += player.vx;
            player.x = Math.max(0, Math.min(canvas.width - player.w, player.x));
            if (player.invul > 0) player.invul--;

            // Shooting
            const fireCooldown = powerUps.rapid > 0 ? 100 : 250;
            if (keys['Space'] && time - gameData.current.lastFire > fireCooldown) {
                bullets.push({ x: player.x + 18, y: player.y });
                gameData.current.lastFire = time;
                sounds.shoot();
            }

            // Power-up durations
            setPowerActive(prev => {
                const next = { rapid: Math.max(0, prev.rapid - 16), shield: Math.max(0, prev.shield - 16) };
                if (next.shield === 0) gameData.current.player.shield = false;
                return next;
            });

            // Parallax
            stars.forEach(s => {
                s.y += s.sp;
                if (s.y > canvas.height) s.y = 0;
            });

            // Bullets
            bullets.forEach((b, i) => {
                b.y -= 12;
                if (b.y < -20) bullets.splice(i, 1);
            });

            // Powerups
            powerups.forEach((p, i) => {
                p.update();
                if (p.y > canvas.height) powerups.splice(i, 1);
                if (p.x < player.x + player.w && p.x + p.w > player.x && p.y < player.y + player.h && p.y + p.h > player.y) {
                    sounds.powerup();
                    if (p.type === 'RAPID') setPowerActive(pa => ({ ...pa, rapid: 5000 }));
                    else { 
                        setPowerActive(pa => ({ ...pa, shield: 8000 })); 
                        gameData.current.player.shield = true; 
                    }
                    powerups.splice(i, 1);
                }
            });

            // Enemies
            if (!boss && time - gameData.current.lastEnemySpawn > spawnRate) {
                enemies.push(new Enemy(canvas.width, speedMult));
                gameData.current.lastEnemySpawn = time;
            }

            enemies.forEach((e, i) => {
                e.update();
                if (e.y > canvas.height) enemies.splice(i, 1);

                // Bullet Hit
                bullets.forEach((b, bi) => {
                    if (b.x > e.x && b.x < e.x + e.w && b.y > e.y && b.y < e.y + e.h) {
                        enemies.splice(i, 1);
                        bullets.splice(bi, 1);
                        const points = e.type === 'BASIC' ? 10 : e.type === 'OSCILLATOR' ? 20 : e.type === 'INTERCEPTOR' ? 30 : 40;
                        setScore(s => s + points);
                        for(let k=0; k<8; k++) particles.push(new Particle(e.x+e.w/2, e.y+e.h/2, `hsl(${e.hue}, 100%, 50%)`));
                        sounds.explosion();
                        if (Math.random() < POWERUP_CHANCE) {
                            powerups.push(new PowerUp(e.x, e.y, Math.random() > 0.5 ? 'RAPID' : 'SHIELD'));
                        }
                    }
                });

                // Player Hit
                if (player.invul === 0 && e.x < player.x + player.w && e.x + e.w > player.x && e.y < player.y + player.h && e.y + e.h > player.y) {
                    enemies.splice(i, 1);
                    hitPlayer();
                }
            });

            // Boss Encounter
            if (score > 0 && score >= (gameData.current.bossDefeatedCount + 1) * 500 && !boss) {
                gameData.current.boss = new Boss(canvas.width, BOSS_BASE_HP + gameData.current.bossDefeatedCount * 20);
                sounds.bossSpawn();
            }

            if (boss) {
                boss.update(canvas.width, time);
                setBossHp({ current: boss.hp, max: boss.maxHp });

                // Boss Patterns
                if (boss.state === 'BARRAGE' && boss.timer % 30 === 0) {
                    for(let angle = -0.5; angle <= 0.5; angle += 0.5) {
                        bossBullets.push({ x: boss.x + boss.w/2, y: boss.y + boss.h, vx: angle * 3, vy: 5 });
                    }
                }
                if (boss.state === 'CRUISE' && Math.random() < 0.03) {
                    bossBullets.push({ x: boss.x + Math.random()*boss.w, y: boss.y + boss.h, vx: 0, vy: 6 });
                }

                // Boss Bullet Collision
                bossBullets.forEach((bb, i) => {
                    bb.x += bb.vx;
                    bb.y += bb.vy;
                    if (bb.y > canvas.height) bossBullets.splice(i, 1);
                    if (player.invul === 0 && bb.x > player.x && bb.x < player.x + player.w && bb.y > player.y && bb.y < player.y + player.h) {
                        bossBullets.splice(i, 1);
                        hitPlayer();
                    }
                });

                // Boss Hit by Player
                bullets.forEach((b, bi) => {
                    if (b.x > boss.x && b.x < boss.x + boss.w && b.y > boss.y && b.y < boss.y + boss.h && boss.state !== 'DYING') {
                        boss.hp--;
                        bullets.splice(bi, 1);
                        if (boss.hp <= 0) {
                            boss.state = 'DYING';
                            gameData.current.bossDefeatedCount++;
                            triggerBossDeath(boss);
                        }
                    }
                });
            }

            particles.forEach((p, i) => {
                p.update();
                if (p.life <= 0) particles.splice(i, 1);
            });

            if (gameData.current.shake > 0) gameData.current.shake *= 0.9;
        };

        const triggerBossDeath = (boss: Boss) => {
            gameData.current.shake = 40;
            for(let i=0; i<50; i++) {
                setTimeout(() => {
                    gameData.current.particles.push(new Particle(boss.x + Math.random()*boss.w, boss.y + Math.random()*boss.h, '#ff00ea'));
                    sounds.explosion();
                }, i * 40);
            }
            setTimeout(() => {
                gameData.current.boss = null;
                setBossHp(null);
                setScore(s => s + 250);
            }, 2000);
        };

        const hitPlayer = () => {
            if (gameData.current.player.shield) {
                gameData.current.player.shield = false;
                // Fix: Corrected undefined variable 'pa' to 'p' within setPowerActive updater function.
                setPowerActive(p => ({ ...p, shield: 0 }));
                gameData.current.player.invul = 30;
                sounds.hit();
                return;
            }
            setLives(l => {
                if (l <= 1) setGameState('GAMEOVER');
                return l - 1;
            });
            gameData.current.player.invul = 60;
            gameData.current.shake = 15;
            sounds.hit();
        };

        const draw = () => {
            ctx.fillStyle = '#050505';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            const { player, enemies, bullets, particles, boss, stars, shake, bossBullets, powerups } = gameData.current;

            ctx.save();
            if (shake > 0.1) ctx.translate((Math.random()-0.5)*shake, (Math.random()-0.5)*shake);

            // Parallax Stars
            stars.forEach(s => {
                ctx.globalAlpha = (s.l + 1) / 3;
                ctx.fillStyle = '#fff';
                ctx.fillRect(s.x, s.y, s.s, s.s);
            });
            ctx.globalAlpha = 1;

            // Power-ups
            powerups.forEach(p => {
                ctx.strokeStyle = p.type === 'RAPID' ? '#00f2ff' : '#ffea00';
                ctx.strokeRect(p.x, p.y, p.w, p.h);
                ctx.fillStyle = ctx.strokeStyle;
                ctx.font = '10px Arial';
                ctx.fillText(p.type[0], p.x + 6, p.y + 14);
            });

            // Player
            if (player.invul % 10 < 5) {
                ctx.shadowBlur = 15;
                ctx.shadowColor = '#00f2ff';
                ctx.strokeStyle = '#00f2ff';
                ctx.lineWidth = 3;
                ctx.beginPath();
                ctx.moveTo(player.x + 20, player.y);
                ctx.lineTo(player.x, player.y + 40);
                ctx.lineTo(player.x + 40, player.y + 40);
                ctx.closePath();
                ctx.stroke();

                if (player.shield) {
                    ctx.strokeStyle = '#ffea00';
                    ctx.setLineDash([5, 5]);
                    ctx.beginPath();
                    ctx.arc(player.x + 20, player.y + 25, 40, 0, Math.PI * 2);
                    ctx.stroke();
                    ctx.setLineDash([]);
                }
            }

            // Bullets
            ctx.fillStyle = '#00f2ff';
            bullets.forEach(b => ctx.fillRect(b.x, b.y, 4, 15));
            ctx.fillStyle = '#ff0044';
            bossBullets.forEach(b => ctx.fillRect(b.x, b.y, 8, 8));

            // Enemies
            enemies.forEach(e => {
                ctx.strokeStyle = `hsl(${e.hue}, 100%, 50%)`;
                ctx.lineWidth = 2;
                ctx.strokeRect(e.x, e.y, e.w, e.h);
                // Simple wing detail
                ctx.beginPath();
                ctx.moveTo(e.x, e.y + 10);
                ctx.lineTo(e.x - 5, e.y + 20);
                ctx.stroke();
            });

            // Boss
            if (boss && boss.state !== 'DYING') {
                ctx.shadowBlur = 30;
                ctx.shadowColor = boss.state === 'CHARGE' ? '#ff0044' : '#ff00ea';
                ctx.strokeStyle = ctx.shadowColor;
                ctx.lineWidth = 4;
                ctx.strokeRect(boss.x, boss.y, boss.w, boss.h);
                ctx.fillStyle = 'rgba(255, 0, 234, 0.1)';
                ctx.fillRect(boss.x, boss.y, boss.w, boss.h);
                // Engine details
                ctx.strokeRect(boss.x + 20, boss.y - 10, 20, 10);
                ctx.strokeRect(boss.x + boss.w - 40, boss.y - 10, 20, 10);
            }

            // Particles
            particles.forEach(p => {
                ctx.globalAlpha = p.life;
                ctx.fillStyle = p.color;
                ctx.fillRect(p.x, p.y, 3, 3);
            });
            ctx.globalAlpha = 1;
            ctx.restore();

            animationFrameId = requestAnimationFrame((t) => {
                update(t);
                draw();
            });
        };

        const onKeyDown = (e: KeyboardEvent) => gameData.current.keys[e.code] = true;
        const onKeyUp = (e: KeyboardEvent) => gameData.current.keys[e.code] = false;
        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        draw();
        return () => {
            cancelAnimationFrame(animationFrameId);
            window.removeEventListener('keydown', onKeyDown);
            window.removeEventListener('keyup', onKeyUp);
            window.removeEventListener('resize', resize);
        };
    }, [gameState, score, powerUps]);

    useEffect(() => {
        if (score > highScore) {
            setHighScore(score);
            localStorage.setItem('galaxyHigh', score.toString());
        }
    }, [score]);

    const handleMobileInput = (key: string, val: boolean) => {
        gameData.current.keys[key] = val;
        if (key === 'Space' && val) sounds.init();
    };

    return (
        <div style={styles.container}>
            <canvas ref={canvasRef} style={styles.canvas} />
            <div style={styles.ui}>
                {gameState === 'START' && (
                    <div style={styles.menu}>
                        <h1 style={styles.title}>GALAXY DEFENDER</h1>
                        <p style={styles.subtitle}>NEON STRIKE V2</p>
                        <p style={{color: '#666'}}>High Score: {highScore}</p>
                        <button style={styles.btn} onClick={startGame}>INITIATE</button>
                    </div>
                )}

                {gameState === 'PLAYING' && (
                    <>
                        <div style={styles.hud}>
                            <div>SCORE: {score}</div>
                            <div>LIVES: {lives}</div>
                        </div>
                        <div style={styles.powerIndicator}>
                            {powerUps.rapid > 0 && <div style={{color: '#00f2ff'}}>RAPID FIRE: {(powerUps.rapid / 1000).toFixed(1)}s</div>}
                            {powerUps.shield > 0 && <div style={{color: '#ffea00'}}>SHIELD: {(powerUps.shield / 1000).toFixed(1)}s</div>}
                        </div>
                        {bossHp && (
                            <div style={styles.bossBarContainer}>
                                <div style={{...styles.bossBar, width: `${(bossHp.current / bossHp.max) * 100}%`}} />
                            </div>
                        )}
                        {'ontouchstart' in window && (
                            <div style={styles.mobileControls}>
                                <div style={styles.dpad}>
                                    <button onTouchStart={() => handleMobileInput('KeyA', true)} onTouchEnd={() => handleMobileInput('KeyA', false)} style={styles.controlBtn}>L</button>
                                    <button onTouchStart={() => handleMobileInput('KeyD', true)} onTouchEnd={() => handleMobileInput('KeyD', false)} style={styles.controlBtn}>R</button>
                                </div>
                                <button onTouchStart={() => handleMobileInput('Space', true)} onTouchEnd={() => handleMobileInput('Space', false)} style={styles.fireBtn}>FIRE</button>
                            </div>
                        )}
                    </>
                )}

                {gameState === 'GAMEOVER' && (
                    <div style={styles.menu}>
                        <h1 style={{...styles.title, color: '#ff0044'}}>SYSTEM FAILURE</h1>
                        <p>Score: {score}</p>
                        <button style={{...styles.btn, borderColor: '#ff0044'}} onClick={startGame}>REBOOT</button>
                    </div>
                )}
            </div>
        </div>
    );
};

