};

createRoot(document.getElementById('root')!).render(<App />);

import React, { useEffect, useRef, useState } from 'react';
import { createRoot } from 'react-dom/client';

// --- Types & Interfaces ---

type GameState = 'START' | 'PLAYING' | 'GAMEOVER';
type EnemyType = 'BASIC' | 'SINE' | 'DIVER' | 'ZIGZAG';
type PowerUpType = 'RAPID_FIRE' | 'SHIELD';

interface Point { x: number; y: number; }

// --- Sound Engine (Synthesized) ---

class SoundEngine {
    ctx: AudioContext | null = null;
    noiseBuffer: AudioBuffer | null = null;

    init() {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
            this.noiseBuffer = this.createNoiseBuffer();
        }
    }

    private createNoiseBuffer() {
        if (!this.ctx) return null;
        const bufferSize = this.ctx.sampleRate * 2;
        const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
        const output = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) {
            output[i] = Math.random() * 2 - 1;
        }
        return buffer;
    }

    private playTone(freq: number, type: OscillatorType, duration: number, volume: number) {
        if (!this.ctx) return;
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();
        osc.type = type;
        osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
        gain.gain.setValueAtTime(volume, this.ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + duration);
        osc.connect(gain);
        gain.connect(this.ctx.destination);
        osc.start();
        osc.stop(this.ctx.currentTime + duration);
    }

    shoot() {
        if (!this.ctx || !this.noiseBuffer) return;
        const noiseSource = this.ctx.createBufferSource();
        noiseSource.buffer = this.noiseBuffer;
        const noiseGain = this.ctx.createGain();
        const duration = 0.08;
        const volume = 0.025;
        noiseGain.gain.setValueAtTime(volume, this.ctx.currentTime);
        noiseGain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + duration);
        const filter = this.ctx.createBiquadFilter();
        filter.type = 'highpass';
        filter.frequency.value = 1000;
        noiseSource.connect(filter);
        filter.connect(noiseGain);
        noiseGain.connect(this.ctx.destination);
        noiseSource.start();
        noiseSource.stop(this.ctx.currentTime + duration);
        this.playTone(880, 'sine', 0.05, 0.01);
    }

    explosion() { this.playTone(60, 'sawtooth', 0.4, 0.08); }
    hit() { this.playTone(150, 'sine', 0.2, 0.05); }
    powerup() { this.playTone(523.25, 'sine', 0.2, 0.05); this.playTone(659.25, 'sine', 0.3, 0.03); }
    bossSpawn() { this.playTone(80, 'sawtooth', 1.0, 0.05); }
}

const sounds = new SoundEngine();

// --- Game Entities ---

class Particle {
    x: number; y: number; vx: number; vy: number;
    life: number = 1.0;
    color: string;
    constructor(x: number, y: number, color: string, vx?: number, vy?: number) {
        this.x = x; this.y = y;
        this.vx = vx ?? (Math.random() - 0.5) * 6;
        this.vy = vy ?? (Math.random() - 0.5) * 6;
        this.color = color;
    }
    update() { this.x += this.vx; this.y += this.vy; this.life -= 0.02; }
}

class PowerUp {
    x: number; y: number; w = 30; h = 30;
    type: PowerUpType;
    pulse: number = 0;
    constructor(x: number, y: number, type: PowerUpType) {
        this.x = x; this.y = y; this.type = type;
    }
    update() {
        this.y += 1.5;
        this.pulse += 0.1;
    }
}

class Enemy {
    x: number; y: number; w: number; h: number; s: number; hue: number;
    type: EnemyType;
    startX: number;
    timer: number = 0;
    hp: number = 1;

    constructor(canvasWidth: number, type: EnemyType, speedBase: number) {
        this.type = type;
        this.w = 40; this.h = 40;
        this.startX = Math.random() * (canvasWidth - this.w);
        this.x = this.startX;
        this.y = -50;

        switch (type) {
            case 'SINE':
                this.hue = 300; // Purple
                this.s = speedBase * 0.9;
                break;
            case 'DIVER':
                this.hue = 0; // Red
                this.s = speedBase * 0.6;
                this.hp = 2; // Tankier
                break;
            case 'ZIGZAG':
                this.hue = 120; // Green
                this.s = speedBase * 1.3;
                break;
            default:
                this.hue = 200; // Blue
                this.s = speedBase;
        }
    }

    update() {
        this.timer++;
        switch (this.type) {
            case 'SINE':
                this.y += this.s;
                this.x = this.startX + Math.sin(this.timer * 0.04) * 120;
                break;
            case 'DIVER':
                if (this.y < 200) this.y += this.s;
                else this.y += this.s * 4.5;
                break;
            case 'ZIGZAG':
                this.y += this.s;
                this.x += Math.sin(this.timer * 0.15) * 8;
                break;
            default:
                this.y += this.s;
        }
    }
}

class Boss {
    x: number; y: number; width: number = 200; height: number = 120;
    hp: number; maxHp: number;
    angle: number = 0;
    state: 'ENTRY' | 'PATTERN_SPIRAL' | 'PATTERN_HOMING' | 'CHARGE' | 'DYING' = 'ENTRY';
    stateTimer: number = 0;
    deathTimer: number = 0;

    constructor(canvasWidth: number, maxHp: number) {
        this.x = canvasWidth / 2 - 100;
        this.y = -200;
        this.hp = maxHp;
        this.maxHp = maxHp;
    }

    update(canvasWidth: number, canvasHeight: number) {
        this.stateTimer++;
        if (this.state === 'ENTRY') {
            if (this.y < 120) this.y += 2.5;
            else this.state = 'PATTERN_SPIRAL';
        } else if (this.state === 'PATTERN_SPIRAL') {
            this.angle += 0.03;
            this.x = (canvasWidth / 2 - 100) + Math.sin(this.angle) * 180;
            if (this.stateTimer > 400) {
                this.state = 'PATTERN_HOMING';
                this.stateTimer = 0;
            }
        } else if (this.state === 'PATTERN_HOMING') {
            this.y = 120 + Math.sin(this.stateTimer * 0.04) * 60;
            this.x += (Math.random() - 0.5) * 15;
            this.x = Math.max(50, Math.min(canvasWidth - this.width - 50, this.x));
            if (this.stateTimer > 350) {
                this.state = 'CHARGE';
                this.stateTimer = 0;
            }
        } else if (this.state === 'CHARGE') {
            if (this.stateTimer < 60) {
                this.y -= 1.5; // Anticipation pullback
            } else {
                this.y += 18; // Massive Charge speed
                if (this.y > canvasHeight + 150) {
                    this.y = -200;
                    this.state = 'ENTRY';
                    this.stateTimer = 0;
                }
            }
        } else if (this.state === 'DYING') {
            this.deathTimer++;
            this.y += 0.3;
            this.x += (Math.random() - 0.5) * 6;
        }
    }
}

// --- Main App Component ---

const App: React.FC = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [gameState, setGameState] = useState<GameState>('START');
    const [score, setScore] = useState(0);
    const [highScore, setHighScore] = useState(Number(localStorage.getItem('neonHigh') || 0));
    const [lives, setLives] = useState(3);
    const [bossHp, setBossHp] = useState<{current: number, max: number} | null>(null);
    const [isMobile] = useState('ontouchstart' in window);

    const gameData = useRef({
        player: { x: 0, y: 0, w: 40, h: 40, vx: 0, invul: 0, shield: 0, rapidFire: 0 },
        bullets: [] as {x: number, y: number}[],
        bossBullets: [] as {x: number, y: number, vx: number, vy: number}[],
        enemies: [] as Enemy[],
        powerups: [] as PowerUp[],
        particles: [] as Particle[],
        stars: [] as {x: number, y: number, s: number, sp: number, l: number}[],
        boss: null as Boss | null,
        shake: 0,
        keys: {} as Record<string, boolean>,
        lastFire: 0,
        lastEnemySpawn: 0,
        startTime: 0,
        bossCount: 0
    });

    const initStars = (w: number, h: number) => {
        gameData.current.stars = Array.from({ length: 180 }, () => {
            const layer = Math.floor(Math.random() * 3);
            return {
                x: Math.random() * w,
                y: Math.random() * h,
                s: layer + 1,
                sp: (layer + 1) * 0.6,
                l: layer
            };
        });
    };

    const startGame = () => {
        sounds.init();
        setGameState('PLAYING');
        setScore(0);
        setLives(3);
        setBossHp(null);
        gameData.current.boss = null;
        gameData.current.enemies = [];
        gameData.current.bullets = [];
        gameData.current.bossBullets = [];
        gameData.current.powerups = [];
        gameData.current.player.invul = 0;
        gameData.current.player.shield = 0;
        gameData.current.player.rapidFire = 0;
        gameData.current.player.vx = 0;
        gameData.current.lastEnemySpawn = performance.now();
        gameData.current.startTime = performance.now();
        gameData.current.bossCount = 0;
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d')!;
        let animationFrameId: number;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            gameData.current.player.x = canvas.width / 2 - 20;
            gameData.current.player.y = canvas.height - 120;
            initStars(canvas.width, canvas.height);
        };
        resize();
        window.addEventListener('resize', resize);

        const handleInput = () => {
            const { keys, player } = gameData.current;
            if (keys['ArrowLeft'] || keys['KeyA']) player.vx -= 1.8;
            if (keys['ArrowRight'] || keys['KeyD']) player.vx += 1.8;
            if (keys['Space']) fire();
        };

        const fire = () => {
            const now = performance.now();
            const { player } = gameData.current;
            const cooldown = player.rapidFire > 0 ? 90 : 250;
            if (now - gameData.current.lastFire > cooldown) {
                gameData.current.bullets.push({ 
                    x: player.x + 18, 
                    y: player.y 
                });
                gameData.current.lastFire = now;
                sounds.shoot();
            }
        };

        const update = (time: number) => {
            const { player, enemies, bullets, particles, boss, stars, bossBullets, powerups } = gameData.current;

            if (gameState === 'PLAYING') {
                handleInput();

                // Dynamic Difficulty Scaling
                const elapsedSeconds = (time - gameData.current.startTime) / 1000;
                const difficultyMultiplier = 1 + (score / 1200) + (elapsedSeconds / 150);
                const enemySpeedBase = 2.2 * difficultyMultiplier;
                const spawnRate = Math.max(250, 1600 / difficultyMultiplier);

                // Player physics
                player.vx *= 0.88;
                player.x += player.vx;
                player.x = Math.max(0, Math.min(canvas.width - player.w, player.x));
                if (player.invul > 0) player.invul--;
                if (player.shield > 0) player.shield--;
                if (player.rapidFire > 0) player.rapidFire--;

                // Stars
                stars.forEach(s => {
                    s.y += s.sp;
                    if (s.y > canvas.height) s.y = 0;
                });

                // Bullets
                bullets.forEach((b, i) => {
                    b.y -= 14;
                    if (b.y < -20) bullets.splice(i, 1);
                });

                // Boss Bullets
                bossBullets.forEach((b, i) => {
                    b.x += b.vx;
                    b.y += b.vy;
                    if (b.y > canvas.height + 50 || b.y < -200 || b.x < -200 || b.x > canvas.width + 200) bossBullets.splice(i, 1);
                    if (player.invul === 0 && b.x > player.x && b.x < player.x + player.w && b.y > player.y && b.y < player.y + player.h) {
                        hitPlayer();
                        bossBullets.splice(i, 1);
                    }
                });

                // Power-ups
                powerups.forEach((p, i) => {
                    p.update();
                    if (p.y > canvas.height) powerups.splice(i, 1);
                    if (p.x < player.x + player.w && p.x + p.w > player.x && p.y < player.y + player.h && p.y + p.h > player.y) {
                        sounds.powerup();
                        if (p.type === 'RAPID_FIRE') player.rapidFire = 500;
                        if (p.type === 'SHIELD') player.shield = 500;
                        powerups.splice(i, 1);
                    }
                });

                // Enemy Spawn
                if (!boss && time - gameData.current.lastEnemySpawn > spawnRate) {
                    const r = Math.random();
                    let type: EnemyType = 'BASIC';
                    if (r > 0.88) type = 'DIVER';
                    else if (r > 0.72) type = 'ZIGZAG';
                    else if (r > 0.55) type = 'SINE';

                    enemies.push(new Enemy(canvas.width, type, enemySpeedBase));
                    gameData.current.lastEnemySpawn = time;
                }

                // Boss Cycle
                if (score > 0 && score >= (gameData.current.bossCount + 1) * 1000 && !boss) {
                    const bossHP = 100 + (gameData.current.bossCount * 50);
                    gameData.current.boss = new Boss(canvas.width, bossHP);
                    gameData.current.bossCount++;
                    sounds.bossSpawn();
                }

                if (boss) {
                    boss.update(canvas.width, canvas.height);
                    setBossHp({current: boss.hp, max: boss.maxHp});

                    if (boss.state !== 'DYING') {
                        // Advanced Boss firing
                        if (boss.state === 'PATTERN_SPIRAL' && boss.stateTimer % 15 === 0) {
                            const spiralAngle = boss.stateTimer * 0.1;
                            bossBullets.push({ 
                                x: boss.x + boss.width / 2, 
                                y: boss.y + boss.height, 
                                vx: Math.cos(spiralAngle) * 4, 
                                vy: Math.sin(spiralAngle) * 4 + 2 
                            });
                        }
                        if (boss.state === 'PATTERN_HOMING' && boss.stateTimer % 40 === 0) {
                            // Targetted burst
                            const dx = (player.x + 20) - (boss.x + boss.width / 2);
                            const dy = (player.y + 20) - (boss.y + boss.height);
                            const dist = Math.sqrt(dx*dx + dy*dy);
                            bossBullets.push({ 
                                x: boss.x + boss.width / 2, 
                                y: boss.y + boss.height, 
                                vx: (dx / dist) * 7, 
                                vy: (dy / dist) * 7 
                            });
                        }

                        bullets.forEach((b, bi) => {
                            if (b.x > boss.x && b.x < boss.x + boss.width && b.y > boss.y && b.y < boss.y + boss.height) {
                                boss.hp--;
                                bullets.splice(bi, 1);
                                if (boss.hp <= 0) {
                                    boss.state = 'DYING';
                                    gameData.current.shake = 20;
                                    sounds.explosion();
                                }
                            }
                        });

                        if (player.invul === 0 && boss.x < player.x + player.w && boss.x + boss.width > player.x && boss.y < player.y + player.h && boss.y + boss.height > player.y) {
                            hitPlayer();
                        }
                    } else {
                        // Death animation refinement
                        if (boss.deathTimer % 4 === 0) {
                            const px = boss.x + Math.random() * boss.width;
                            const py = boss.y + Math.random() * boss.height;
                            particles.push(new Particle(px, py, '#ff00ea'));
                            if (boss.deathTimer % 12 === 0) {
                                sounds.explosion();
                                gameData.current.shake = 5;
                            }
                        }
                        if (boss.deathTimer > 150) {
                            for (let i = 0; i < 60; i++) {
                                particles.push(new Particle(
                                    boss.x + boss.width / 2, 
                                    boss.y + boss.height / 2, 
                                    '#ff00ea', 
                                    (Math.random() - 0.5) * 20, 
                                    (Math.random() - 0.5) * 20
                                ));
                            }
                            setScore(s => s + 750);
                            gameData.current.boss = null;
                            setBossHp(null);
                        }
                    }
                }

                enemies.forEach((e, i) => {
                    e.update();
                    if (e.y > canvas.height + 60) enemies.splice(i, 1);

                    bullets.forEach((b, bi) => {
                        if (b.x > e.x && b.x < e.x + e.w && b.y > e.y && b.y < e.y + e.h) {
                            e.hp--;
                            bullets.splice(bi, 1);
                            if (e.hp <= 0) {
                                enemies.splice(i, 1);
                                let p = 10;
                                if (e.type === 'SINE') p = 25;
                                if (e.type === 'ZIGZAG') p = 35;
                                if (e.type === 'DIVER') p = 60;
                                setScore(s => s + p);
                                for(let k=0; k<12; k++) particles.push(new Particle(e.x+e.w/2, e.y+e.h/2, `hsl(${e.hue}, 100%, 50%)`));
                                sounds.explosion();

                                if (Math.random() < 0.18) {
                                    powerups.push(new PowerUp(e.x, e.y, Math.random() > 0.6 ? 'RAPID_FIRE' : 'SHIELD'));
                                }
                            } else {
                                sounds.hit();
                            }
                        }
                    });

                    if (e.x < player.x + player.w && e.x + e.w > player.x && e.y < player.y + player.h && e.y + e.h > player.y && player.invul === 0) {
                        enemies.splice(i, 1);
                        hitPlayer();
                    }
                });

                particles.forEach((p, i) => {
                    p.update();
                    if (p.life <= 0) particles.splice(i, 1);
                });
            }

            if (gameData.current.shake > 0) gameData.current.shake *= 0.92;
        };

        const hitPlayer = () => {
            const { player } = gameData.current;
            if (player.shield > 0) {
                player.shield = 0;
                player.invul = 60;
                sounds.hit();
                return;
            }
            setLives(l => {
                const next = l - 1;
                if (next <= 0) setGameState('GAMEOVER');
                return next;
            });
            player.invul = 100;
            gameData.current.shake = 40;
            sounds.hit();
        };

        const draw = () => {
            ctx.fillStyle = '#050505';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            const { player, enemies, bullets, particles, boss, stars, shake, bossBullets, powerups } = gameData.current;

            ctx.save();
            if (shake > 0.1) ctx.translate((Math.random()-0.5)*shake, (Math.random()-0.5)*shake);

            stars.forEach(s => {
                ctx.globalAlpha = (s.l + 1) / 3.5;
                ctx.fillStyle = '#fff';
                ctx.fillRect(s.x, s.y, s.s, s.s);
            });
            ctx.globalAlpha = 1;

            powerups.forEach(p => {
                const s = 1 + Math.sin(p.pulse) * 0.2;
                ctx.shadowBlur = 20;
                ctx.shadowColor = p.type === 'RAPID_FIRE' ? '#ff00ea' : '#ffea00';
                ctx.strokeStyle = ctx.shadowColor;
                ctx.lineWidth = 3;
                ctx.strokeRect(p.x + (p.w - p.w*s)/2, p.y + (p.h - p.h*s)/2, p.w*s, p.h*s);
                ctx.fillStyle = ctx.shadowColor;
                ctx.font = 'bold 20px Arial';
                ctx.fillText(p.type === 'RAPID_FIRE' ? 'R' : 'S', p.x + 7, p.y + 22);
            });

            // Player Render
            if (player.invul % 12 < 6) {
                ctx.shadowBlur = 20;
                ctx.shadowColor = '#00f2ff';
                ctx.strokeStyle = '#00f2ff';
                ctx.lineWidth = 4;
                ctx.beginPath();
                ctx.moveTo(player.x + 20, player.y);
                ctx.lineTo(player.x - 5, player.y + 45);
                ctx.lineTo(player.x + 45, player.y + 45);
                ctx.closePath();
                ctx.stroke();

                if (player.shield > 0) {
                    ctx.strokeStyle = '#ffea00';
                    ctx.shadowColor = '#ffea00';
                    ctx.setLineDash([10, 5]);
                    ctx.beginPath();
                    ctx.arc(player.x + 20, player.y + 28, 50, 0, Math.PI * 2);
                    ctx.stroke();
                    ctx.setLineDash([]);
                }
            }

            ctx.fillStyle = player.rapidFire > 0 ? '#ff00ea' : '#00f2ff';
            bullets.forEach(b => ctx.fillRect(b.x, b.y, 5, 20));
            ctx.fillStyle = '#ff0044';
            bossBullets.forEach(b => ctx.fillRect(b.x, b.y, 10, 10));

            enemies.forEach(e => {
                ctx.strokeStyle = `hsl(${e.hue}, 100%, 50%)`;
                ctx.shadowBlur = 10;
                ctx.shadowColor = ctx.strokeStyle;
                ctx.lineWidth = 3;
                if (e.type === 'DIVER') {
                    ctx.beginPath(); // Diamond for divers
                    ctx.moveTo(e.x + 20, e.y);
                    ctx.lineTo(e.x + 40, e.y + 20);
                    ctx.lineTo(e.x + 20, e.y + 40);
                    ctx.lineTo(e.x, e.y + 20);
                    ctx.closePath();
                    ctx.stroke();
                } else if (e.type === 'SINE') {
                    ctx.beginPath(); // Hexagon for sine
                    for(let i=0; i<6; i++) {
                        const ang = (i * Math.PI * 2) / 6;
                        const px = e.x + 20 + Math.cos(ang) * 20;
                        const py = e.y + 20 + Math.sin(ang) * 20;
                        if(i===0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
                    }
                    ctx.closePath();
                    ctx.stroke();
                } else {
                    ctx.strokeRect(e.x, e.y, e.w, e.h);
                }
            });

            if (boss) {
                ctx.shadowBlur = boss.state === 'DYING' ? 40 : 30;
                ctx.shadowColor = boss.state === 'CHARGE' ? '#ff0044' : '#ff00ea';
                ctx.strokeStyle = ctx.shadowColor;
                ctx.lineWidth = 6;
                ctx.strokeRect(boss.x, boss.y, boss.width, boss.height);
                ctx.fillStyle = 'rgba(255, 0, 234, 0.1)';
                ctx.fillRect(boss.x, boss.y, boss.width, boss.height);
                // Wings/Engines
                ctx.strokeRect(boss.x - 20, boss.y + 20, 20, 60);
                ctx.strokeRect(boss.x + boss.width, boss.y + 20, 20, 60);
            }

            particles.forEach(p => {
                ctx.globalAlpha = p.life;
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, 2.5, 0, Math.PI*2);
                ctx.fill();
            });
            ctx.globalAlpha = 1;

            ctx.restore();
            animationFrameId = requestAnimationFrame((t) => {
                update(t);
                draw();
            });
        };

        const onKeyDown = (e: KeyboardEvent) => gameData.current.keys[e.code] = true;
        const onKeyUp = (e: KeyboardEvent) => gameData.current.keys[e.code] = false;
        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        draw();
        return () => {
            cancelAnimationFrame(animationFrameId);
            window.removeEventListener('keydown', onKeyDown);
            window.removeEventListener('keyup', onKeyUp);
            window.removeEventListener('resize', resize);
        };
    }, [gameState, score]);

    useEffect(() => {
        if (score > highScore) {
            setHighScore(score);
            localStorage.setItem('neonHigh', score.toString());
        }
    }, [score]);

    const handleMobileInput = (key: string, val: boolean) => {
        gameData.current.keys[key] = val;
        if (key === 'Space' && val) sounds.init();
    };

    return (
        <div style={styles.container}>
            <canvas ref={canvasRef} style={styles.canvas} />

            <div style={styles.ui}>
                {gameState === 'START' && (
                    <div style={styles.menu}>
                        <h1 style={styles.title}>GALAXY DEFENDER</h1>
                        <p style={styles.subtitle}>NEON STRIKE V2: RECHARGED</p>
                        <p style={{color: '#666', fontSize: '1.2rem', marginBottom: '20px'}}>High Score: {highScore}</p>
                        <button style={styles.btn} onClick={startGame}>INITIATE MISSION</button>
                        <div style={styles.instructions}>
                            [WASD / ARROWS] TO MOVE &bull; [SPACE] TO FIRE
                        </div>
                    </div>
                )}

                {gameState === 'PLAYING' && (
                    <>
                        <div style={styles.hud}>
                            <div style={styles.scoreText}>SCORE: {score}</div>
                            <div style={styles.livesText}>LIVES: {'❤️'.repeat(lives)}</div>
                        </div>
                        <div style={styles.powerupList}>
                            {gameData.current.player.rapidFire > 0 && <div style={{color:'#ff00ea'}}>RAPID FIRE ACTIVE</div>}
                            {gameData.current.player.shield > 0 && <div style={{color:'#ffea00'}}>SHIELD ACTIVE</div>}
                        </div>
                        {bossHp !== null && (
                            <div style={styles.bossBarContainer}>
                                <div style={styles.bossName}>NEON ANNIHILATOR</div>
                                <div style={styles.bossBarOuter}>
                                    <div style={{...styles.bossBarInner, width: `${(bossHp.current / bossHp.max) * 100}%`}} />
                                </div>
                            </div>
                        )}
                        {isMobile && (
                            <div style={styles.mobileControls}>
                                <div style={styles.dpad}>
                                    <button 
                                        onTouchStart={() => handleMobileInput('KeyA', true)} 
                                        onTouchEnd={() => handleMobileInput('KeyA', false)}
                                        style={styles.controlBtn}>LEFT</button>
                                    <button 
                                        onTouchStart={() => handleMobileInput('KeyD', true)} 
                                        onTouchEnd={() => handleMobileInput('KeyD', false)}
                                        style={styles.controlBtn}>RIGHT</button>
                                </div>
                                <button 
                                    onTouchStart={() => handleMobileInput('Space', true)} 
                                    onTouchEnd={() => handleMobileInput('Space', false)}
                                    style={styles.fireBtn}>FIRE</button>
                            </div>
                        )}
                    </>
                )}

                {gameState === 'GAMEOVER' && (
                    <div style={styles.menu}>
                        <h1 style={{...styles.title, color: '#ff0044'}}>MISSION FAILED</h1>
                        <p style={{fontSize: '2.2rem', marginBottom: '30px'}}>Final Score: {score}</p>
                        <button style={{...styles.btn, borderColor: '#ff0044', color: '#ff0044'}} onClick={startGame}>RETRY MISSION</button>
                    </div>
                )}
            </div>
        </div>
    );
};

